import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        q = int(next(it))
        for _ in range(q):
            x = int(next(it)); y = int(next(it))
            s = x + y
            # binary search
            lo, hi = 0, n
            while lo < hi:
                mid = (lo + hi) // 2
                if a[mid] < s:
                    lo = mid + 1
                else:
                    hi = mid
            if lo < n and a[lo] == s:
                out_lines.append('-1')
            else:
                out_lines.append(str(lo))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

