const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let out = [];
for (let tc = 0; tc < T; tc++) {
  const N = input[idx++];
  const a = input.slice(idx, idx + N);
  idx += N;
  const Q = input[idx++];
  for (let i = 0; i < Q; i++) {
    const x = input[idx++];
    const y = input[idx++];
    const s = x + y;
    // lower_bound
    let l = 0, r = N;
    while (l < r) {
      const m = (l + r) >> 1;
      if (a[m] < s) l = m + 1; else r = m;
    }
    if (l < N && a[l] === s) out.push('-1');
    else out.push(String(l));
  }
}
